  { name: 'D', rating: 4 },
  { name: 'E', rating: 3 },
  { name: 'F', rating: 3 },
  { name: 'G', rating: 4 },
  { name: 'H', rating: 3 },
  { name: 'I', rating: 2 },
  { name: 'J', rating: 2 },
  { name: 'K', rating: 2 },
];
